function formatDate(date, type) {
  if (!type) {
    if (date.substring(0, 4) == 3000) {
      return "长期有效";
    } else {
      return date.substring(0, 4) + "年" + date.substring(5, 7) + "月" + date.substring(8, 10) + "日";
    }
  } else {
    return date.substring(0, 4) + "" + type + date.substring(5, 7) + "" + type + date.substring(8, 10);
  }
}
